package main

import "fmt"

func countSquares(matrix [][]int) int {
	max := len(matrix)
	if len(matrix[0]) < max {
		max = len(matrix[0])
	}

	count := 0
	for side := 0; side < max; side++ {
		for row := 0; row < len(matrix)-side; row++ {
			for column := 0; column < len(matrix[0])-side; column++ {
				if side == 0 {
					if matrix[row][column] == 1 {
						count += 1
					}
				} else {
					filled := true
					for hor := 0; hor <= side; hor++ {
						for ver := 0; ver <= side; ver++ {
							if matrix[row+hor][column+ver] == 0 {
								filled = false
								break
							}
						}
						if !filled {
							break
						}
					}
					if filled {
						count += 1
					}
				}
			}
		}
	}

	return count
}

